// Prepare data for dedup check
const jobData = $json;
let triggerData = {};
try { triggerData = $('Execute Workflow Trigger').item?.json || {}; } catch(e) { triggerData = {}; }

const company = triggerData['Company'] || jobData['Company'] || '';
const title = triggerData['Job Title'] || jobData['Job Title'] || '';
const source = triggerData['Source'] || jobData['Source'] || 'Unknown';

return {
  json: {
    company: company,
    title: title,
    source: source,
    recordType: 'job',
    _originalJobData: triggerData
  }
};

// Handle duplicate - skip evaluation but return info
const dedupResult = $json;

// Get _originalJobData from the dedup result (passed through from Dedup Check Subworkflow)
const originalJob = dedupResult._originalJobData || {};

return {
  json: {
    _skipped: true,
    _skipReason: 'duplicate',
    _existingRecordId: dedupResult.existingRecordId,
    _allSources: dedupResult.allSources,
    _key: dedupResult.key,
    'Job Title': originalJob['Job Title'],
    'Company': originalJob['Company'],
    'Source': originalJob['Source'],
    _emailId: originalJob._emailId
  }
};

// Restore original job data for processing
const dedupResult = $json;

// Get _originalJobData from the dedup result (passed through from Dedup Check Subworkflow)
const originalJobData = dedupResult._originalJobData || {};

return {
  json: {
    ...originalJobData,
    _dedupKey: dedupResult.key
  }
};

// Parse Job Description from HTML
let braveData = {};
let jobData = {};
let httpResult = {};

try { braveData = $('Brave Search Company').item?.json || {}; } catch(e) { console.error('Parse JD: Failed to get Brave data:', e.message); braveData = {}; }
try { jobData = $('Restore Job Data').item?.json || {}; } catch(e) { console.error('Parse JD: Failed to get job data:', e.message); jobData = {}; }
try { httpResult = $('Fetch JD (HTTP)').item?.json || {}; } catch(e) { console.error('Parse JD: Failed to get HTTP result:', e.message); httpResult = {}; }

let html = '';
let fetchSource = 'none';

try {
  const browserlessResult = $('Fetch JD (Browserless)').item.json;
  if (browserlessResult && (browserlessResult.data || typeof browserlessResult === 'string')) {
    html = browserlessResult.data || browserlessResult;
    fetchSource = 'browserless';
  }
} catch (e) {
  if (httpResult && (httpResult.data || typeof httpResult === 'string')) {
    html = httpResult.data || httpResult;
    fetchSource = 'http';
  }
}

if (!html && httpResult) {
  if (typeof httpResult === 'string' && httpResult.length > 500) {
    html = httpResult;
    fetchSource = 'http';
  } else if (httpResult.data && httpResult.data.length > 500) {
    html = httpResult.data;
    fetchSource = 'http';
  }
}

let htmlStr = typeof html === 'string' ? html : JSON.stringify(html || '');

// v6.4 FIX: Truncate HTML before regex matching to prevent catastrophic backtracking
const MAX_HTML_LENGTH = 50000;
if (htmlStr.length > MAX_HTML_LENGTH) {
  console.error(`Warning: HTML truncated from ${htmlStr.length} to ${MAX_HTML_LENGTH} chars to prevent regex backtracking`);
  htmlStr = htmlStr.substring(0, MAX_HTML_LENGTH);
}

const selectorPatterns = [
  /<div[^>]*class="[^"]*content[^"]*"[^>]*>([\s\S]*?)<\/div>/gi,
  /<div[^>]*class="[^"]*posting-description[^"]*"[^>]*>([\s\S]*?)<\/div>/gi,
  /<div[^>]*data-automation-id="[^"]*jobPostingDescription[^"]*"[^>]*>([\s\S]*?)<\/div>/gi,
  /<div[^>]*class="[^"]*job[-_]?description[^"]*"[^>]*>([\s\S]*?)<\/div>/gi,
  /<section[^>]*class="[^"]*job[-_]?description[^"]*"[^>]*>([\s\S]*?)<\/section>/gi,
  /<div[^>]*id="jobDescriptionText"[^>]*>([\s\S]*?)<\/div>/gi,
  /<div[^>]*class="[^"]*description__text[^"]*"[^>]*>([\s\S]*?)<\/div>/gi,
  /<div[^>]*class="[^"]*ashby-job-posting-description[^"]*"[^>]*>([\s\S]*?)<\/div>/gi
];

let extractedText = '';
for (const pattern of selectorPatterns) {
  const matches = htmlStr.match(pattern);
  if (matches && matches.length > 0) {
    const longestMatch = matches.reduce((a, b) => a.length > b.length ? a : b);
    extractedText = longestMatch;
    break;
  }
}

if (!extractedText || extractedText.length < 200) {
  const mainMatch = htmlStr.match(/<main[^>]*>([\s\S]*?)<\/main>/gi);
  const articleMatch = htmlStr.match(/<article[^>]*>([\s\S]*?)<\/article>/gi);
  if (mainMatch && mainMatch[0].length > (extractedText?.length || 0)) {
    extractedText = mainMatch[0];
  } else if (articleMatch && articleMatch[0].length > (extractedText?.length || 0)) {
    extractedText = articleMatch[0];
  }
}

function cleanHtml(html) {
  return html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<\/?(p|div|br|li|h[1-6]|tr)[^>]*>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .replace(/\n\s*\n/g, '\n\n')
    .trim();
}

const cleanedText = cleanHtml(extractedText || '');
const quality = cleanedText.length > 1000 ? 'high' : cleanedText.length > 300 ? 'medium' : cleanedText.length > 0 ? 'low' : 'failed';
const maxLength = 6000;
const truncatedText = cleanedText.length > maxLength ? cleanedText.substring(0, maxLength) + '\n\n[...truncated]' : cleanedText;

let jdSource = 'none';
if (!jobData['Job URL']) {
  jdSource = 'no_url';
} else if (quality === 'failed') {
  jdSource = 'fetch_failed';
} else {
  jdSource = fetchSource;
}

return {
  json: {
    ...braveData,
    _jobData: jobData,
    _fetchedJobDescription: truncatedText,
    _jdSource: jdSource,
    _jdQuality: quality,
    _jdLength: cleanedText.length
  }
};

// v6.7: Added merger/rebrand detection (pe-merger-detection-v1.1)
// v6.6: Batch 4 fixes - Employee corroboration, CX tooling detection, Funding recency, Suspicious employee cross-ref
// v6.3: Aligned thresholds to agent lens v2.13, added sector gates, persona gate, JD-based gates
// Changes from v6.2:
// - Employee hard DQ: 1000 -> 200 (matching agent lens)
// - Employee penalty zone: 150-200 at -20pts (matching agent lens)
// - Added 27+ sector detection patterns (ported from company pipeline v9.7)
// - Added developer-as-customer persona gate
// - Added JD-text-based pre-scoring gates (NRR language, IT support, scale signals, maintainer density)
// - Added stalled company detection
// - Funding penalties aligned to agent lens

const jdParseResult = $json;
let triggerData = {};
try { triggerData = $('Restore Job Data').item?.json || {}; } catch(e) { console.error('Failed to get Restore Job Data:', e.message); triggerData = {}; }
const jobData = jdParseResult._jobData || triggerData;
let braveData = {};
try { braveData = $('Brave Search Company').item?.json || {}; } catch(e) { console.error('Failed to get Brave Search data:', e.message); braveData = {}; }
const braveResults = braveData.web?.results || [];

const fetchedJD = jdParseResult._fetchedJobDescription || '';
const jdSource = jdParseResult._jdSource || 'none';
const jdQuality = jdParseResult._jdQuality || 'none';

// Network connections registry
const NETWORK_CONNECTIONS = {
  'google': {
    level: 'VP Connection',
    note: 'VP-level contact at Google; not preferred fit but worth pursuing via networking advantage',
    overrideDisqualifiers: ['TOO_LARGE', 'FUNDING_TOO_HIGH', 'PUBLIC']
  }
};

let enrichment = {
  employeeCount: null,
  fundingStage: null,
  totalFunding: null,
  isPEBacked: false,
  isVCBacked: false,
  foundedYear: null,
  companyAge: null,
  enrichmentSource: null,
  rawSnippets: []
};

const combinedText = braveResults.map(r => `${r.title || ''} ${r.description || ''}`).join(' ');
const combinedTextLower = combinedText.toLowerCase();
enrichment.rawSnippets = braveResults.slice(0, 3).map(r => (r.description || '').substring(0, 200));

// === EMPLOYEE COUNT EXTRACTION ===
const empPatterns = [
  /(\d{1,3}(?:,\d{3})*)\s*(?:\+\s*)?employees/i,
  /(\d{1,3}(?:,\d{3})*)\s*(?:-|to|–)\s*(\d{1,3}(?:,\d{3})*)\s*employees/i,
  /employees?:?\s*(\d{1,3}(?:,\d{3})*)/i,
  /team\s+(?:of\s+)?(\d{1,3}(?:,\d{3})*)/i,
  /headcount:?\s*(\d{1,3}(?:,\d{3})*)/i
];

for (const pattern of empPatterns) {
  const match = combinedText.match(pattern);
  if (match) {
    const num1 = parseInt((match[1] || '').replace(/,/g, ''));
    const num2 = match[2] ? parseInt(match[2].replace(/,/g, '')) : null;
    enrichment.employeeCount = num2 ? Math.max(num1, num2) : num1;
    break;
  }
}

// === FUNDING STAGE EXTRACTION ===
const stagePatterns = [
  { pattern: /(?:ipo|went public|publicly traded|nasdaq|nyse)/i, stage: 'Public' },
  { pattern: /series\s*[d-z]\b/i, stage: 'Series D+' },
  { pattern: /series\s*c\b/i, stage: 'Series C' },
  { pattern: /series\s*b\b/i, stage: 'Series B' },
  { pattern: /series\s*a\b/i, stage: 'Series A' },
  { pattern: /seed\s+(?:round|funding|stage)/i, stage: 'Seed' },
  { pattern: /pre[-\s]?seed/i, stage: 'Pre-Seed' },
  { pattern: /bootstrapped/i, stage: 'Bootstrapped' }
];

for (const { pattern, stage } of stagePatterns) {
  if (pattern.test(combinedText)) {
    enrichment.fundingStage = stage;
    break;
  }
}

// === FUNDING AMOUNT EXTRACTION ===
const fundingPatterns = [
  /(?:raised|funding|total\s+funding)[^$]*\$([\d.]+)\s*(billion)\b/i,
  /(?:raised|funding|total\s+funding)[^$]*\$([\d.]+)\s*(million|m)\b/i,
  /\$([\d.]+)\s*(billion)\s*(?:raised|funding|in\s+funding)/i,
  /\$([\d.]+)\s*(million|m)\s*(?:raised|funding|in\s+funding)/i,
  /(?:funding|raised):\s*\$([\d.]+)\s*(billion|million|m)?/i
];

for (const pattern of fundingPatterns) {
  const match = combinedText.match(pattern);
  if (match) {
    let amount = parseFloat(match[1]);
    const unit = (match[2] || 'm').toLowerCase();
    if (unit === 'billion') amount *= 1000;
    enrichment.totalFunding = amount;
    break;
  }
}

// === VALUATION EXTRACTION (v6.4: ported from v9.8 for unicorn gate) ===
let valuation = null, valuationRaw = null;
if (/unicorn/i.test(combinedText)) {
  valuation = 1000000000;
  valuationRaw = '$1.0B (unicorn)';
} else {
  const valuationPatterns = [
    /valued\s+at\s+\$([\d.]+)\s*(million|billion|M|B)/gi,
    /valuation\s+(?:of\s+)?\$([\d.]+)\s*(million|billion|M|B)/gi
  ];
  for (const pattern of valuationPatterns) {
    let match;
    while ((match = pattern.exec(combinedText)) !== null) {
      let amount = parseFloat(match[1]);
      const unit = (match[2] || '').toLowerCase();
      if (unit === 'billion' || unit === 'b') amount *= 1000000000;
      else if (unit === 'million' || unit === 'm') amount *= 1000000;
      if (amount > (valuation || 0)) {
        valuation = amount;
        const valStr = amount >= 1000000000 ? `$${(amount / 1000000000).toFixed(1)}B` : `$${(amount / 1000000).toFixed(0)}M`;
        valuationRaw = valStr;
      }
    }
  }
}
enrichment.valuation = valuation;
enrichment.valuationRaw = valuationRaw;

// === PE / VC DETECTION ===
const PE_FIRMS = [
  'vista equity', 'thoma bravo', 'kkr', 'blackstone', 'carlyle',
  'bain capital', 'tpg', 'apollo', 'warburg pincus', 'silver lake',
  'francisco partners', 'ares management', 'golden gate capital',
  'insight partners', 'vector capital', 'ta associates', 'nordic capital',
  'hellman friedman', 'permira', 'advent international', 'cinven',
  'eqt partners', 'cvc capital', 'bc partners', 'apax partners',
  'general atlantic', 'summit partners', 'providence equity',
  'welsh carson', 'gtcr', 'leonard green', 'american securities',
  'clearlake capital', 'platinum equity', 'kohlberg',
  'accel-kkr', 'brighton park capital', 'softbank vision fund',
  'jonas software', 'constellation software', 'volaris',
  'harris computer', 'spring lake equity', 'ares capital'
];

// v6.6: CX Tooling Keywords (Batch 4 Fix 4.4 - companies that SELL to support teams)
const CX_TOOLING_KEYWORDS = ['cobrowsing', 'session replay', 'helpdesk', 'ticketing', 'chatbot', 'customer support software', 'live chat', 'contact center', 'support automation', 'knowledge base software', 'customer service platform', 'help desk software', 'support ticketing'];

// v6.7: MERGER/REBRAND DETECTION (from pe-merger-detection-v1.1)
const mergerKeywords = [
  'built on the collective expertise of', 'built on the expertise of',
  'newly combined companies', 'newly combined', 'combined companies',
  'bringing together', 'formed from the merger', 'formed by the combination',
  'union of', 'resulting from the merger', 'combination of', 'emerged from',
  'successor to', 'born from the union',
  'formerly known as', 'now known as', 'rebranded as', 'rebranded from',
  'now operating as', 'doing business as', 'unified under', 'operating under the',
  'evolution of', 'legacy of', 'continuation of',
  'f/k/a', 'fka', 'd/b/a', 'dba',
  'powered by', 'backed by', 'platform company', 'portfolio company',
  'operating company of', 'family of companies', 'member of the', 'a part of the',
  'growth investment from', 'recapitalized by', 'majority owned by',
  'joined forces', 'integration of', 'platform acquisition', 'roll-up', 'rollup',
  'consolidation of', 'combined entity', 'merged entity', 'add-on acquisition', 'tuck-in acquisition'
];
const hasMergerSignal = mergerKeywords.some(kw => combinedTextLower.includes(kw));

// v6.7: Expanded acquisition patterns with merger/rebrand
const mergerAcquirePatterns = [
  /acquired\s+by\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s+(?:in|for|from|,|\.)|$)/i,
  /bought\s+by\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s+(?:in|for|from|,|\.)|$)/i,
  /merged\s+with\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s+(?:in|to|,|\.)|$)/i,
  /part\s+of\s+([A-Z][a-zA-Z0-9&]+(?:\s+(?:Group|Holdings|Capital|Inc|Corp|Partners|Equity))?)(?:\s|,|\.|$)/i,
  /portfolio\s+company\s+of\s+([A-Z][a-zA-Z0-9&]+(?:\s+(?:Capital|Partners|Equity))?)(?:\s|,|\.|$)/i,
  /backed\s+by\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s|,|\.|$)/i,
  /powered\s+by\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s|,|\.|$)/i,
  /built\s+on\s+(?:the\s+)?(?:collective\s+)?expertise\s+of\s+([A-Z][a-zA-Z0-9&\s]+)/i,
  /bringing\s+together\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)\s+(?:and|&|\+)/i,
  /formerly\s+known\s+as\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s|,|\.|$)/i,
  /rebranded\s+(?:from|as)\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s|,|\.|$)/i,
  /f\/k\/a\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s|,|\.|$)/i,
  /fka\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s|,|\.|$)/i
];
let mergerAcquirerName = null;
for (const pattern of mergerAcquirePatterns) {
  const match = combinedText.match(pattern);
  if (match && match[1]) { mergerAcquirerName = match[1].trim().substring(0, 50); break; }
}

// v6.7: Predecessor name extraction
let predecessorNames = [];
if (hasMergerSignal) {
  const combinationPatterns = [
    /expertise\s+of\s+([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)\s*(?:\+|and|&)\s*([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)(?:[.,;:]|\s+(?:and|to|now|bringing|delivering|creating|combining|with)\b|\s*$)/i,
    /bringing\s+together\s+([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)\s*(?:\+|and|&)\s*([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)(?:[.,;:]|\s|$)/i,
    /(?:merger|combination|union)\s+of\s+([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)\s*(?:\+|and|&)\s*([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)(?:[.,;:]|\s|$)/i,
    /(?:formerly\s+known\s+as|f\/k\/a|fka)\s+([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)(?:[.,;:]|\s+(?:and|now|,)|\s*$)/i,
    /rebranded\s+from\s+([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)(?:[.,;:]|\s+(?:to|as)|\s*$)/i,
    /(?:powered|backed)\s+by\s+([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)(?:[.,;:]|\s|$)/i
  ];
  for (const pattern of combinationPatterns) {
    const match = combinedText.match(pattern);
    if (match) {
      if (match[1]) predecessorNames.push(match[1].trim());
      if (match[2]) predecessorNames.push(match[2].trim());
      break;
    }
  }
  predecessorNames = [...new Set(predecessorNames)].map(n => n.replace(/\s+/g, ' ').trim()).filter(n => n.length > 2 && n.length < 60);
}

// v6.7: Generate merger DQ reason
let mergerDQReason = null;
if (hasMergerSignal && predecessorNames.length > 0 && !enrichment.isPEBacked) {
  mergerDQReason = 'MERGER_DETECTED: Needs ownership verification (' + predecessorNames.join(' + ') + ')';
} else if (hasMergerSignal && !enrichment.isPEBacked) {
  mergerDQReason = 'MERGER_DETECTED: Needs manual ownership verification';
}

const pePatterns = /private\s+equity|pe[-\s]backed|buyout|lbo|acquired\s+by.*(?:capital|partners)/i;
const peByName = PE_FIRMS.some(firm => combinedTextLower.includes(firm));
const vcPatterns = /venture\s+capital|vc[-\s]backed|backed\s+by|investors?\s+include|a16z|sequoia|accel|greylock|benchmark|andreessen/i;

enrichment.isPEBacked = pePatterns.test(combinedText) || peByName;
enrichment.isVCBacked = vcPatterns.test(combinedText) && !enrichment.isPEBacked;

// === FOUNDED YEAR ===
const foundedPatterns = [
  /founded\s*(?:in\s*)?(\d{4})/i,
  /established\s*(?:in\s*)?(\d{4})/i,
  /since\s+(\d{4})/i,
  /started\s*(?:in\s*)?(\d{4})/i
];

for (const pattern of foundedPatterns) {
  const match = combinedText.match(pattern);
  if (match) {
    const year = parseInt(match[1]);
    if (year >= 1900 && year <= new Date().getFullYear()) {
      enrichment.foundedYear = year;
      enrichment.companyAge = new Date().getFullYear() - year;
      break;
    }
  }
}

if (braveResults.length > 0) {
  const crunchbaseResult = braveResults.find(r => r.url?.includes('crunchbase.com'));
  enrichment.enrichmentSource = crunchbaseResult?.url || braveResults[0].url;
}

// === ACQUISITION DETECTION ===
let isAcquired = false;
let acquiredBy = null;
const acquirePatterns = [
  /acquired\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /bought\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /merged\s+with\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /subsidiary\s+of\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /now\s+owned\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i
];
for (const pattern of acquirePatterns) {
  const match = combinedText.match(pattern);
  if (match) {
    isAcquired = true;
    acquiredBy = match[1]?.trim().substring(0, 50) || 'Unknown';
    break;
  }
}
if (!isAcquired && /\b(was acquired|has been acquired|acquired in \d{4}|formerly|shut down|shuttered|defunct)\b/i.test(combinedText)) {
  isAcquired = true;
}

// === v6.3: SECTOR DETECTION (ported from company pipeline v9.7) ===
const isBiotech = /\b(therapeutic|biologics|drug development|clinical trial|FDA approval|cell therapy|gene therapy|pharma|pharmaceutical|biotech|oncology|immunotherapy)\b/i.test(combinedText);
const isHardware = /\b(hardware|sensors|devices|robotics|manufacturing|chip|semiconductor|solar|battery|EV charging|physical product|wearable)\b/i.test(combinedText) && !/\b(SaaS|software platform|cloud platform|API)\b/i.test(combinedText);
const isCrypto = /\b(blockchain|cryptocurrency|web3|NFT|DeFi|token|crypto|decentralized)\b/i.test(combinedText);
const isConsumer = /\b(consumer app|DTC|direct-to-consumer|e-commerce|retail brand|B2C|telehealth|patient app|consumer health|consumer marketplace)\b/i.test(combinedText);
const isHRTech = /\b(HR tech|human resources|DEI|diversity equity|workforce analytics|recruiting platform|HRIS|payroll|applicant tracking)\b/i.test(combinedText);
const isClimateHardware = /\b(carbon capture|solar panel|wind turbine|EV infrastructure|grid storage|climate tech hardware)\b/i.test(combinedText);
const isAgTech = /\b(agriculture|farming|aquaculture|fishery|livestock|agtech)\b/i.test(combinedText) && !/\b(SaaS|software|platform)\b/i.test(combinedText);
const isMarketplace = /\b(marketplace|two-sided market|gig economy|freelance platform|labor marketplace)\b/i.test(combinedText) && !/\b(SaaS|software platform|enterprise)\b/i.test(combinedText);

const isHealthcareCareDelivery = /\b(our (?:physicians|clinicians|doctors|therapists|providers)|patients can (?:access|schedule|receive)|(?:telehealth|virtual) (?:visits|appointments|care)|care delivery|value-based care|employs (?:physicians|clinicians)|board-certified (?:physicians|doctors)|medical group|clinical services|patient care services)\b/i.test(combinedText) && !/\b(provider-facing|clinician workflow|EHR integration|healthcare operations|clinical workflow automation)\b/i.test(combinedText);
const isMedicalDevice = /\b(medical device|(?:FDA|CE) (?:cleared|approved|approval)|(?:wearable|diagnostic|monitoring) device|brain stimulation|hormone monitoring|clinical device)\b/i.test(combinedText);
const isCybersecurity = /\b(cybersecurity|cyber security|SBOM|supply chain security|vulnerability management|threat detection|penetration testing|endpoint protection|malware detection)\b/i.test(combinedText);
const isLegalTech = /\b(legal tech|legaltech|law firm software|legal AI|case management software|e-discovery|legal research|contract lifecycle|CLM|legal operations)\b/i.test(combinedText);
const isEdTech = /\b(ed-?tech|learning (?:platform|management)|LMS|educational technology|student learning|classroom technology|tutoring platform|educational assessment)\b/i.test(combinedText);
const isPropertyManagement = /\b(property management|real estate tech|proptech|landlord software|tenant management|rental management|commercial real estate|CRE tech)\b/i.test(combinedText);
const isTaxTech = /\b(tax (?:automation|credit|software)|R&D tax credit|tax compliance|tax filing|tax preparation software)\b/i.test(combinedText);
const isSalesTools = /\b(sales (?:engagement|enablement|automation)|digital sales room|sales intelligence|revenue intelligence|conversation intelligence|sales coaching|quota management)\b/i.test(combinedText);
const isVeterinary = /\b(veterinary|vet tech|animal health|pet health|veterinarian software|vet practice management)\b/i.test(combinedText);
const isFintech = /\b(fintech|banking software|credit union|neobank|payment processing|lending platform|loan origination|mortgage tech|banking as a service|BaaS|open banking|core banking)\b/i.test(combinedText) && !/\b(healthcare billing|medical billing|revenue cycle)\b/i.test(combinedText);
const isConstructionTech = /\b(construction (?:tech|software|management|billing|payments)|general contractor|subcontractor management|job site|building information|BIM software|AEC industry)\b/i.test(combinedText);
const isFoodBiotech = /\b(fermentation|food science|food tech|cultured (?:meat|protein)|alternative protein|CPG brand|consumer packaged goods|beverage brand|food manufacturing|flavor (?:company|technology)|ingredient(?:s)? company)\b/i.test(combinedText);
const isPhysicalSecurity = /\b(physical security|access control|surveillance|security camera|weapon detection|metal detector|security screening|perimeter security)\b/i.test(combinedText) && !/\b(cybersecurity|data security|cloud security)\b/i.test(combinedText);
const isInsurtech = /\b(insurtech|insurance (?:technology|software|platform)|policy management|claims processing|underwriting (?:platform|software)|insurance marketplace|actuarial)\b/i.test(combinedText) && !/\b(healthcare|health plan|benefits administration)\b/i.test(combinedText);
const isSaaSManagement = /\b(SaaS management|software spend|IT asset management|license management|shadow IT|SaaS operations|IT procurement|vendor management platform)\b/i.test(combinedText);
const isConsumerDigitalHealth = /\b(mental health app|therapy app|meditation app|wellness app|patient (?:portal|app|engagement)|health coaching app|symptom checker|self-care|digital therapeutic|DTx|behavioral health app|fertility app|pregnancy app|breastfeeding|lactation)\b/i.test(combinedText) && !/\b(provider-facing|clinician-facing|EHR|clinical workflow|healthcare operations)\b/i.test(combinedText);
const isAICalling = /\b(AI (?:calling|phone|receptionist|voice agent)|automated (?:calling|phone calls)|voice AI (?:agent|assistant)|robocall|call automation|phone bot|AI answering)\b/i.test(combinedText) && !/\b(contact center|call center software|customer support platform)\b/i.test(combinedText);

const sectorDQ = [];
if (isBiotech) sectorDQ.push('Biotech/pharma (not B2B SaaS)');
if (isHardware || isClimateHardware) sectorDQ.push('Hardware/Physical product');
if (isAgTech) sectorDQ.push('AgTech/Aquaculture');
if (isCrypto) sectorDQ.push('Crypto/Web3');
if (isHRTech) sectorDQ.push('HR Tech/DEI');
if (isConsumer) sectorDQ.push('Consumer/B2C/Telehealth');
if (isMarketplace) sectorDQ.push('Marketplace');
if (isHealthcareCareDelivery) sectorDQ.push('Healthcare care delivery (not SaaS)');
if (isMedicalDevice) sectorDQ.push('Medical device/hardware');
if (isCybersecurity) sectorDQ.push('Cybersecurity (wrong sector)');
if (isLegalTech) sectorDQ.push('Legal Tech (wrong sector)');
if (isEdTech) sectorDQ.push('Ed-tech (wrong sector)');
if (isPropertyManagement) sectorDQ.push('Property Management/Real Estate Tech');
if (isTaxTech) sectorDQ.push('Tax automation (wrong sector)');
if (isSalesTools) sectorDQ.push('Sales tools (wrong buyer persona)');
if (isVeterinary) sectorDQ.push('Veterinary (wrong sector)');
if (isFintech) sectorDQ.push('Fintech/Banking (wrong sector)');
if (isConstructionTech) sectorDQ.push('Construction Tech (wrong sector)');
if (isFoodBiotech) sectorDQ.push('Food science/CPG (not B2B SaaS)');
if (isPhysicalSecurity) sectorDQ.push('Physical security hardware (wrong sector)');
if (isInsurtech) sectorDQ.push('Insurtech (wrong sector)');
if (isSaaSManagement) sectorDQ.push('SaaS management/IT spend (wrong buyer persona)');
if (isConsumerDigitalHealth) sectorDQ.push('Consumer digital health (patient-facing, not provider SaaS)');
if (isAICalling) sectorDQ.push('AI calling/voice agent (not enterprise CS)');

// === v6.3: DEVELOPER-AS-CUSTOMER PERSONA GATE ===
const DEVELOPER_CUSTOMER_SIGNALS = [
  /\bfor developers\b/i,
  /\bdeveloper (?:platform|tools?|experience|workflow|productivity)\b/i,
  /\bAPI[-\s]?first\b/i,
  /\bSDK\b/i,
  /\bdev(?:ops)? (?:platform|tools?)\b/i,
  /\binfrastructure (?:as code|platform|tool)\b/i,
  /\bCI[\s/]?CD\b/i,
  /\bcode (?:review|quality|analysis|coverage)\b/i,
  /\bopen[\s-]?source (?:project|tool|framework|library)\b/i,
  /\bcontainer(?:ization)?|docker|kubernetes\b/i,
  /\bserverless\b/i,
  /\bheadless (?:CMS|API|platform)\b/i,
  /\bdeveloper community\b/i,
  /\bdeveloper relations|devrel\b/i,
  /\bsoftware engineers? (?:use|love|trust|choose)\b/i
];

const ENTERPRISE_DEV_TOOL_SIGNALS = [
  /enterprise (?:developer|engineering) (?:platform|tools)/i,
  /\benterprise plan\b/i,
  /\baccount executive\b/i,
  /\benterprise customers?\b/i,
  /\bFortune (?:500|1000|100)\b/i,
  /\bSOC ?2\b/i,
  /\bSSO\b/i,
  /\baudit log\b/i
];

// Check both Brave results AND JD text for persona signals
const personaText = combinedText + ' ' + fetchedJD;
const devCustomerSignalCount = DEVELOPER_CUSTOMER_SIGNALS.filter(p => p.test(personaText)).length;
const enterpriseDevSignalCount = ENTERPRISE_DEV_TOOL_SIGNALS.filter(p => p.test(personaText)).length;
const isDeveloperCustomer = devCustomerSignalCount >= 2;
const hasEnterpriseSalesMotionForDevTool = enterpriseDevSignalCount >= 2;
const isDeveloperCustomerDQ = isDeveloperCustomer && !hasEnterpriseSalesMotionForDevTool && (!enrichment.employeeCount || enrichment.employeeCount < 50);

// === v6.3: JD-TEXT-BASED PRE-SCORING GATES ===
const jdText = fetchedJD || '';
const jdLower = jdText.toLowerCase();

// NRR-first language detection (agent lens: NRR in first 2 bullets = auto-DQ)
// Check if retention/renewal language appears in the first ~500 chars of JD
const jdOpening = jdLower.substring(0, 500);
const NRR_FIRST_PATTERNS = [
  /\bnrr\b/i, /net revenue retention/i, /gross retention/i, /\bgrr\b/i,
  /renewal forecasting/i, /renewal rate/i, /retention rate/i,
  /book of business/i, /portfolio of accounts/i,
  /retention targets/i, /churn reduction/i
];
const nrrFirstCount = NRR_FIRST_PATTERNS.filter(p => p.test(jdOpening)).length;
const isNRRFirstRole = nrrFirstCount >= 2;

// IT Support / Help Desk / Technical Support detection from title
const jobTitle = (jobData['Job Title'] || '').toLowerCase();
const isITSupport = /\b(it support|help desk|helpdesk|technical support|desktop support|service desk|IT service)\b/i.test(jobTitle);

// Scale signals in JD (agent lens: auto-DQ)
const SCALE_SIGNALS = [
  /\b\d{3,}M\+? users\b/i, /500\+?\s*(?:million|M) users/i,
  /\b\d{3,}\+?\s*enterprise (?:clients|customers|accounts)\b/i,
  /Fortune 500 partners/i,
  /\b\d{4,}\+?\s*(?:customers|clients|accounts)\b/i
];
const hasScaleSignals = SCALE_SIGNALS.some(p => p.test(jdText));

// Maintainer density detection
const MAINTAINER_SIGNALS = [
  /lead and scale existing/i, /scale our (?:global|existing)/i,
  /manage (?:global|distributed) teams? of \d{2,}/i, /oversee multi-tier/i,
  /day-to-day operations/i, /queue management/i, /SLA performance/i,
  /optimize existing processes/i, /proven playbook/i, /playbook already/i,
  /inherit(?:ing)? (?:a |an |the )?(?:\d+ person |existing |established )/i,
  /Tier 1.*Tier 2.*Tier 3/i, /multiple tiers/i,
  /consumer .* enterprise support/i
];
const BUILDER_SIGNALS = [
  /build from scratch/i, /first (?:hire|support|CS|customer)/i,
  /founding (?:team|member|hire)/i, /greenfield/i,
  /define (?:the )?playbook/i, /create (?:the )?(?:processes|team|org)/i,
  /ground up/i, /0 to 1/i, /zero to one/i,
  /establish (?:the )?(?:team|function|org)/i,
  /player[\s-]?coach/i, /hands[\s-]?on/i,
  /no existing (?:team|support|CS)/i
];
const maintainerCount = MAINTAINER_SIGNALS.filter(p => p.test(jdText)).length;
const builderCount = BUILDER_SIGNALS.filter(p => p.test(jdText)).length;
const isHeavyMaintainer = maintainerCount >= 3 && builderCount === 0;

// === BUILD DISQUALIFICATION & PENALTY LISTS (v6.3: aligned to agent lens v2.13) ===
enrichment.autoDisqualifiers = [];
enrichment.scoringPenalties = [];
enrichment.sectorFlags = sectorDQ;
enrichment.jdFlags = [];

// HARD GATES (matching agent lens)
if (enrichment.isPEBacked) enrichment.autoDisqualifiers.push('PE-backed company');
if (mergerDQReason) enrichment.autoDisqualifiers.push(mergerDQReason);
if (isAcquired) enrichment.autoDisqualifiers.push(`Acquired${acquiredBy ? ' by ' + acquiredBy : ''}`);
if (enrichment.fundingStage === 'Public') enrichment.autoDisqualifiers.push('Public company');
if (['Series D+'].includes(enrichment.fundingStage)) enrichment.autoDisqualifiers.push(`Late stage (${enrichment.fundingStage})`);

// v6.4: Employee hard DQ at 350 (aligned to v9.8 company pipeline)
if (enrichment.employeeCount && enrichment.employeeCount > 350) {
  enrichment.autoDisqualifiers.push(`${enrichment.employeeCount} employees (>350 = CS function already exists)`);
}

// v6.3: Funding hard DQ at $500M (was $500M, matches)
if (enrichment.totalFunding && enrichment.totalFunding >= 500) {
  const fundingDisplay = enrichment.totalFunding >= 1000 ? `$${(enrichment.totalFunding / 1000).toFixed(1)}B` : `$${enrichment.totalFunding}M`;
  enrichment.autoDisqualifiers.push(`${fundingDisplay} funding (>=$500M)`);
}

// v6.4: Unicorn valuation gate (>$1B = DQ, aligned to v9.8)
if (enrichment.valuation && enrichment.valuation >= 1000000000) {
  enrichment.autoDisqualifiers.push(`Unicorn valuation (>$1B: ${enrichment.valuationRaw})`);
}

// SECTOR GATES
if (sectorDQ.length > 0) enrichment.autoDisqualifiers.push(...sectorDQ);

// PERSONA GATE
if (isDeveloperCustomerDQ) enrichment.autoDisqualifiers.push('Developer-as-customer persona (<50 employees, no enterprise sales motion)');

// JD-BASED GATES
if (isITSupport) enrichment.autoDisqualifiers.push('IT Support/Help Desk/Technical Support (role type exclusion)');
if (isNRRFirstRole) enrichment.autoDisqualifiers.push('NRR-first role language (retention/renewal-focused, not builder)');
if (hasScaleSignals) enrichment.jdFlags.push('Scale signals in JD (>500M users, >500 enterprise clients, Fortune 500 partners)');

// SCORING PENALTIES (aligned to agent lens v2.13)
// v6.4: 200-350 employees = -20 pts penalty zone (aligned to v9.8 company pipeline)
if (enrichment.employeeCount && enrichment.employeeCount >= 200 && enrichment.employeeCount <= 350) {
  enrichment.scoringPenalties.push(`${enrichment.employeeCount} employees (200-350 penalty zone): -20 pts`);
}

// Funding penalties
if (enrichment.totalFunding && enrichment.totalFunding >= 200 && enrichment.totalFunding < 500) {
  enrichment.scoringPenalties.push(`$${enrichment.totalFunding}M funding (200-499M): -15 pts`);
} else if (enrichment.totalFunding && enrichment.totalFunding >= 100 && enrichment.totalFunding < 200) {
  enrichment.scoringPenalties.push(`$${enrichment.totalFunding}M funding (100-199M): -10 pts`);
}

// Series C penalty
if (enrichment.fundingStage === 'Series C') {
  enrichment.scoringPenalties.push('Series C: -10 pts');
}

// Title penalty: Support without Director/VP/Head
const hasSupportInTitle = /\bsupport\b/i.test(jobTitle);
const hasSeniorTitle = /\b(director|vp|vice president|head|svp|chief)\b/i.test(jobTitle);
if (hasSupportInTitle && !hasSeniorTitle) {
  enrichment.scoringPenalties.push('Support role without Director/VP/Head title: -15 pts');
}

// Stalled company detection
const currentYear = new Date().getFullYear();

// v6.6: Funding recency extraction (Batch 4 Fix 4.2)
let lastFundingYear = null;
let yearsSinceLastRound = null;
let fundingRecency = null;
const fundingYearPatterns = [
  /series\s*[a-e]\s*(?:round\s*)?(?:in\s*)?(20\d{2})/i,
  /raised.*?(20\d{2})/i,
  /(20\d{2}).*?series\s*[a-e]/i,
  /(?:funding|round).*?(20\d{2})/i
];
for (const pattern of fundingYearPatterns) {
  const match = combinedText.match(pattern);
  if (match) {
    const year = parseInt(match[1]);
    if (year >= 2015 && year <= currentYear && (!lastFundingYear || year > lastFundingYear)) {
      lastFundingYear = year;
    }
  }
}
if (lastFundingYear) {
  yearsSinceLastRound = currentYear - lastFundingYear;
  if (yearsSinceLastRound < 1) fundingRecency = 'recent';
  else if (yearsSinceLastRound < 2) fundingRecency = 'moderate';
  else if (yearsSinceLastRound < 3) fundingRecency = 'aging';
  else fundingRecency = 'stale';
}

// v6.6: Graduated funding staleness modifier (Batch 4 Fix 4.2)
const isEarlyStage = ['Seed', 'Series A', 'Pre-Seed'].includes(enrichment.fundingStage);
let fundingStalenessModifier = 0;
if (yearsSinceLastRound && isEarlyStage && (!enrichment.employeeCount || enrichment.employeeCount < 100)) {
  if (yearsSinceLastRound >= 4) fundingStalenessModifier = -15;
  else if (yearsSinceLastRound >= 3) fundingStalenessModifier = -10;
  else if (yearsSinceLastRound >= 2) fundingStalenessModifier = -5;
}

// v6.6: CX Tooling Company Detection (Batch 4 Fix 4.4)
let isCXToolingCompany = false;
let cxToolingSignals = [];
for (const keyword of CX_TOOLING_KEYWORDS) { if (combinedTextLower.includes(keyword.toLowerCase())) { cxToolingSignals.push(keyword); } }
isCXToolingCompany = cxToolingSignals.length >= 2;

// v6.6: Suspicious employee count cross-reference (Batch 4 Fix 4.1)
const fundingStageRank = { 'Pre-Seed': 1, 'Seed': 2, 'Series A': 3, 'Series B': 4, 'Series C': 5, 'Series D+': 6 };
const isSeriesAPlus = enrichment.fundingStage && fundingStageRank[enrichment.fundingStage] >= 3;
const hasSignificantFunding = enrichment.totalFunding && enrichment.totalFunding >= 10;
let suspiciousEmployeeCount = false;
let employeeCountFlag = null;
if (enrichment.employeeCount && enrichment.employeeCount < 15 && (isSeriesAPlus || hasSignificantFunding)) {
  suspiciousEmployeeCount = true;
  employeeCountFlag = 'Employee count ' + enrichment.employeeCount + ' seems low for ' + (enrichment.fundingStage || 'significant funding');
}
if (enrichment.companyAge && enrichment.companyAge >= 10) {
  const earlyStages = ['Seed', 'Pre-Seed', 'Bootstrapped', null];
  const isStillEarly = earlyStages.includes(enrichment.fundingStage);
  const isSmall = !enrichment.employeeCount || enrichment.employeeCount < 350;
  if (isStillEarly && isSmall) {
    enrichment.autoDisqualifiers.push(`Stalled company (${enrichment.companyAge}yr old, still ${enrichment.fundingStage || 'early stage'}, <350 emp)`);
  }
}

// Mature company penalty (>5yr at Series B+)
const growthStages = ['Series B', 'Series C', 'Series D+', 'Growth'];
if (enrichment.companyAge && enrichment.companyAge > 5 && growthStages.includes(enrichment.fundingStage)) {
  enrichment.scoringPenalties.push(`Founded ${enrichment.foundedYear} (${enrichment.companyAge}yr old at ${enrichment.fundingStage}): -5 pts`);
}

// JD-based flags (not DQ, but passed to Claude)
if (isHeavyMaintainer) enrichment.jdFlags.push('Heavy maintainer language in JD (3+ signals, 0 builder signals)');
if (isDeveloperCustomer && !isDeveloperCustomerDQ) enrichment.jdFlags.push('Developer-as-customer (passed gate: enterprise motion detected)');
// v6.6: Batch 4 warnings
if (isCXToolingCompany) enrichment.jdFlags.push('CX tooling company (sells TO support teams): ' + cxToolingSignals.join(', '));
if (suspiciousEmployeeCount) enrichment.jdFlags.push('Suspicious employee count: ' + employeeCountFlag);
if (fundingStalenessModifier < 0) enrichment.jdFlags.push('Funding staleness penalty: ' + fundingStalenessModifier + ' pts');

// Network connection override
const companyLower = (jobData['Company'] || '').toLowerCase();
let networkConnection = null;
for (const [key, conn] of Object.entries(NETWORK_CONNECTIONS)) {
  if (companyLower.includes(key)) {
    networkConnection = conn;
    const overrideable = ['employees (>350', 'funding (>=$500M)', 'Public company'];
    const originalCount = enrichment.autoDisqualifiers.length;
    enrichment.autoDisqualifiers = enrichment.autoDisqualifiers.filter(d => !overrideable.some(o => d.includes(o)));
    if (enrichment.autoDisqualifiers.length < originalCount) {
      enrichment.connectionOverride = `${conn.level}: ${originalCount - enrichment.autoDisqualifiers.length} disqualifier(s) overridden`;
    }
    break;
  }
}

return {
  json: {
    ...jobData,
    _enrichment: enrichment,
    _networkConnection: networkConnection,
    _braveResultCount: braveResults.length,
    _hasAutoDisqualifier: enrichment.autoDisqualifiers.length > 0,
    _isDeveloperCustomer: isDeveloperCustomer,
    _maintainerSignalCount: maintainerCount,
    _builderSignalCount: builderCount,
    'Job Description': fetchedJD || jobData['Job Description'] || jobData['Description'] || '',
    _jdSource: jdSource,
    _jdQuality: jdQuality,
    // v6.6: Batch 4 fields
    _lastFundingYear: lastFundingYear,
    _yearsSinceLastRound: yearsSinceLastRound,
    _fundingRecency: fundingRecency,
    _hasMergerSignal: hasMergerSignal,
    _predecessorNames: predecessorNames,
    _mergerDQReason: mergerDQReason,
    _fundingStalenessModifier: fundingStalenessModifier,
    _isCXToolingCompany: isCXToolingCompany,
    _cxToolingSignals: cxToolingSignals.join(', '),
    _suspiciousEmployeeCount: suspiciousEmployeeCount,
    _employeeCountFlag: employeeCountFlag
  }
};

// v6.3: Focused scoring prompt, removed full agent lens stuffing
// Changes from v6.2:
// - System prompt is a focused scoring rubric, NOT the entire 640-line agent lens
// - Added CS Hire Readiness as scoring dimension (was missing)
// - Rebalanced scoring: Stage 30pts (was 50), CS Readiness 25pts (new), Role 25pts (was 30), Mission 20pts (same)
// - Added explicit wrong-sector/wrong-model score floor guidance
// - Passes enrichment warnings, sector flags, and JD flags to Claude

const jobData = $json;

if (jobData._empty || jobData._skip) {
  return { json: { ...jobData, _skip: true } };
}

const enrichment = jobData._enrichment || {};
const networkConnection = jobData._networkConnection || null;

const systemPrompt = `You are a job matching assistant evaluating roles for a specific candidate.

=== CANDIDATE PROFILE ===
Name: Eric Zelman
Current: Job searching (laid off June 2025)
Background: 13+ years at Bigtincan as founding customer-facing hire. Built CS/support org from 0 to 25 people across 3 continents. $130M B2B SaaS, 1,500+ customers, 13 products, 250+ Fortune 1000 enterprise clients, 2M+ users, 15,000+ annual cases, 93%+ CSAT.
Prior: Support Engineer at Apperian (early-stage mobile SaaS, 60 Fortune 1000 customers), Territory Manager at HP/Palm, Account Executive at Alliance HealthCare (medical imaging), Account Executive & Systems Engineer at Apple (Harvard/Tufts enterprise accounts).
Target: Founding or first CS/support leadership role at VC-backed B2B SaaS companies. Series A/B, 20-100 employees, under ~$75M total funding.
Location: Providence RI. Open to remote, relocation to SF or NYC.
Healthcare experience: PROVIDER-SIDE (not payer). Medical imaging equipment, not pharma marketing.
AWS Cloud Architecture certification (completed).

=== CRITICAL DISTINCTION: BUILDER vs MAINTAINER ===
This candidate wants BUILDER roles (creating from scratch) NOT MAINTAINER roles.

BUILDER signals (score HIGH on role_type):
- "Build from scratch", "first hire", "founding team", "greenfield"
- "Define playbook", "create processes", "establish team"
- Series A/B startup, <50 employees, no/tiny existing CS team
- "Player-coach", "hands-on", "0 to 1"

MAINTAINER signals (HARD CAP role_type at 5 points):
- "Lead and scale existing organization", "scale our global support"
- "Manage global teams of 30+", "oversee multi-tier support"
- "Day-to-day operations", "queue management", "SLA performance"
- "Optimize existing processes", "proven playbook already in place"
- "Book of business", "portfolio of accounts", "retention targets", "renewal rate"
- Multiple tiers already exist (Tier 1, Tier 2, Tier 3 mentioned)
- Consumer + Enterprise support already separated

=== AUTO-DISQUALIFIERS ===
If ANY of these are true, set is_dealbreaker=true and score=0:
- PE/Growth Equity backed
- >350 employees (CS function already exists)
- >$500M total funding or valuation
- Fortune 500 or public company
- Acquired, shut down, or defunct
- Series D+ or Growth stage
- Wrong sector: Biotech, hardware, crypto, consumer, HR Tech, legal tech, cybersecurity, fintech, construction tech, physical security, food/CPG, insurance, SaaS management, veterinary, consumer digital health, AI calling/voice agents
- Wrong business model: Care delivery, marketplace, consulting, staffing
- IT Support / Help Desk / Technical Support (internal-facing)
- NRR-first language in opening of JD (retention/renewal-focused, not builder)
- Developer-as-customer persona at <50 employees without enterprise sales motion
- Domain expertise required in: pharma marketing, financial services, legal, AdTech, government, Web3

=== SCORING (100 points total) ===

1. COMPANY STAGE & SIZE (30 points max)
   - 30 = Pre-A to Series A, 10-50 employees (sweet spot)
   - 25 = Series B, 30-80 employees
   - 20 = Late Seed or early Series B, appropriate size
   - 10 = Series C, 100-350 employees
   - 5 = Larger but has builder signal
   - 0 = Too early (<15 emp) or too late (>350 emp)

2. CS HIRE READINESS (25 points max) - CRITICAL FACTOR
   - 25 = Clearly first CS/support hire, no existing function
   - 20 = Very small team (<5), needs senior leadership
   - 15 = Small team (<10), building out org
   - 10 = Team exists but scaling, builder opportunity unclear
   - 5 = Established team, incremental hire
   - 0 = No evidence of CS hiring need, or large existing CS org

   If you see NO evidence of CS hire readiness, score 0-5. Do not assume readiness from stage.

3. ROLE MANDATE (25 points max)
   BUILDER (20-25 points): "First hire", "build from scratch", "greenfield", "define playbook"
   HYBRID (10-15 points): Mix of build and scale signals
   MAINTAINER (HARD CAP AT 5): Managing existing org, optimizing, scaling 30+ person team
   NO EVIDENCE (5-8 points): Cannot determine mandate from available info

4. MISSION ALIGNMENT (20 points max)
   - 20 = Healthcare B2B SaaS (provider-side), Enterprise AI (high-touch, compliance, governance)
   - 15 = Developer tools with enterprise sales motion, regulated industry tools
   - 10 = Enterprise B2B SaaS (high-touch)
   - 5 = General B2B SaaS
   - 0 = Wrong sector (consumer, fintech, legal, etc.)

   WRONG SECTOR = 0 POINTS. Do not give partial credit for stage if sector is wrong.

=== SCORING PENALTIES (deduct from total) ===
- 200-350 employees: -20 pts
- Total funding $200M-$500M: -15 pts
- Total funding $100M-$200M: -10 pts
- Series C: -10 pts
- Support title without Director/VP/Head: -15 pts
- Founded >5yr ago at Series B+: -5 pts
- On-site outside acceptable cities: -10 pts
- Compensation <$125K base: -10 pts

=== BONUSES ===
- Founded <3 years ago: +10 pts
- VC-backed (not PE): +10 pts
- B-Corp certified: +10 pts
- Direct founder relationship / network connection: +15 pts

=== SCORE CALIBRATION ===
- 80-100: STRONG FIT. Apply immediately.
- 60-79: GOOD FIT. Research and likely apply.
- 40-59: MARGINAL. Only if exceptional factors.
- Below 40: SKIP. Not aligned.
- Below 20: HARD PASS. Wrong sector, wrong model, or fundamental misfit.

A company with good stage but WRONG SECTOR should score 10-25.
A company with right sector but NO CS HIRE SIGNAL should score 15-30.
A company with wrong sector AND no CS signal should score 0-15.

=== TITLE FLEXIBILITY ===
At companies <50 people, title is irrelevant. "Director" at a 25-person Series A has more scope than "VP" at a 2,000-person company. Focus on builder scope, not title.

=== NETWORK CONNECTION OVERRIDE ===
When indicated, do NOT auto-disqualify on size/funding/public. Score the role on its own merits honestly. Note networking advantage but don't inflate score.

=== RESPONSE FORMAT ===
Respond with ONLY valid JSON:
{
  "score": <0-100>,
  "role_type": "builder" | "maintainer" | "hybrid",
  "is_dealbreaker": <true/false>,
  "dealbreaker_reason": "<reason if dealbreaker, null otherwise>",
  "score_breakdown": {
    "company_stage_fit": <0-30>,
    "cs_hire_readiness": <0-25>,
    "role_mandate": <0-25>,
    "mission_alignment": <0-20>
  },
  "penalties_applied": ["<penalty description>"],
  "bonuses_applied": ["<bonus description>"],
  "builder_evidence": ["<quotes/signals>"],
  "maintainer_evidence": ["<quotes/signals>"],
  "industry": "<company industry>",
  "company_stage_detected": "<pre_a|series_a|series_b|series_c|growth|late|public|unknown>",
  "company_size_detected": "<number or range or null>",
  "salary_detected": { "base_min": null, "base_max": null, "has_equity": null },
  "what_excites": ["<alignment factors>"],
  "concerns": ["<red flags>"],
  "recommendation": "apply" | "research" | "skip",
  "summary": "<2-3 sentence assessment focused on builder fit and CS hire readiness>"
}`;

const fundingDisplay = enrichment.totalFunding ? (enrichment.totalFunding >= 1000 ? '$' + (enrichment.totalFunding / 1000).toFixed(1) + 'B' : '$' + enrichment.totalFunding + 'M') : 'Unknown';

const enrichmentBlock = `
COMPANY ENRICHMENT DATA (from web search - USE THIS FOR SCORING):
- Employee Count: ${enrichment.employeeCount || 'Unknown'}
- Funding Stage: ${enrichment.fundingStage || 'Unknown'}
- Total Funding: ${fundingDisplay}
- PE-Backed: ${enrichment.isPEBacked ? 'YES - AUTO-DISQUALIFIER!' : 'No'}
- VC-Backed: ${enrichment.isVCBacked ? 'Yes (+10 bonus)' : 'Unknown'}
- Founded: ${enrichment.foundedYear || 'Unknown'}${enrichment.companyAge ? ' (' + enrichment.companyAge + ' years old)' : ''}${enrichment.companyAge && enrichment.companyAge <= 3 ? ' - RECENT (+10 bonus)' : ''}
- Acquired: ${enrichment.autoDisqualifiers.some(d => d.startsWith('Acquired')) ? 'YES - AUTO-DISQUALIFIER!' : 'No'}
- Enrichment Source: ${enrichment.enrichmentSource || 'No results found'}
${enrichment.autoDisqualifiers?.length > 0 ? '\nAUTO-DISQUALIFIERS DETECTED: ' + enrichment.autoDisqualifiers.join(', ') : ''}
${enrichment.scoringPenalties?.length > 0 ? '\nSCORING PENALTIES TO APPLY: ' + enrichment.scoringPenalties.join(', ') : ''}
${enrichment.sectorFlags?.length > 0 ? '\nSECTOR FLAGS: ' + enrichment.sectorFlags.join(', ') : ''}
${enrichment.jdFlags?.length > 0 ? '\nJD FLAGS: ' + enrichment.jdFlags.join(', ') : ''}
${networkConnection ? '\nNETWORK CONNECTION: ' + networkConnection.level + ' - ' + networkConnection.note + (enrichment.connectionOverride ? ' (' + enrichment.connectionOverride + ')' : '') : ''}
${jobData._isDeveloperCustomer ? '\nDEVELOPER-AS-CUSTOMER: Yes (passed gate: enterprise motion or 50+ employees)' : ''}
${jobData._isCXToolingCompany ? '\nCX TOOLING COMPANY: YES - This company SELLS customer support software (signals: ' + jobData._cxToolingSignals + '). These companies sell TO support teams, NOT build large CS orgs. Set cs_hire_readiness=0-5 and mark as unlikely to hire CS leadership.' : ''}
${jobData._fundingRecency === 'stale' ? '\nSTALE FUNDING: Last funding ' + jobData._yearsSinceLastRound + ' years ago. Apply -' + Math.abs(jobData._fundingStalenessModifier || 0) + ' penalty.' : ''}
${jobData._suspiciousEmployeeCount ? '\nSUSPICIOUS EMPLOYEE COUNT: ' + jobData._employeeCountFlag : ''}
`;

const jobDescription = jobData['Job Description'] || jobData['Description'] || '';
const descriptionNote = jobDescription ? `\n\nJOB DESCRIPTION:\n${jobDescription.substring(0, 4000)}` : '\n\nNote: Full job description not available. Analyze based on title, company context, and enrichment data.';

// Pass builder/maintainer signal counts from enrichment
const signalNote = (jobData._builderSignalCount || jobData._maintainerSignalCount) ?
  `\nJD SIGNAL ANALYSIS: ${jobData._builderSignalCount || 0} builder signals, ${jobData._maintainerSignalCount || 0} maintainer signals detected in JD text.` : '';

const userPrompt = `Analyze this job posting.

JOB POSTING:
Title: ${jobData['Job Title']}
Company: ${jobData['Company']}
Location: ${jobData['Location']}
Salary: ${jobData['Salary Info'] || 'Not specified'}
Source: ${jobData['Source']}
${enrichmentBlock}${signalNote}${descriptionNote}

If auto-disqualifiers are present, set is_dealbreaker=true and score=0. Otherwise, apply the scoring framework and return JSON.
REMINDER: Wrong sector = 0 mission points. No CS hire evidence = 0-5 readiness points. Do not inflate scores.`;

return {
  json: {
    ...jobData,
    _systemPrompt: systemPrompt,
    _userPrompt: userPrompt
  }
};

// v6.6: Batch 4 - Added CS Hire Readiness score capping and funding staleness modifier
// v6.3: Updated to parse new score_breakdown fields (cs_hire_readiness, penalties, bonuses)
// Source preservation fix from v6.1 retained
const input = $json;
let jobData = {};
try { jobData = $('Build Prompt').item?.json || {}; } catch(e) { console.error('Parse Response: Failed to get Build Prompt data:', e.message); jobData = {}; }
if (!jobData['Job Title'] && input['Job Title']) { jobData = input; }
if (!jobData['Company'] && input['Company']) { jobData['Company'] = input['Company']; }

// v6.1 FIX: Explicitly preserve Source with multiple fallbacks
let sourceValue = jobData['Source'];
if (!sourceValue) {
  try { sourceValue = $('Restore Job Data').item?.json?.['Source']; } catch(e) { console.error('Parse Response: Restore Job Data source fallback failed:', e.message); }
}
if (!sourceValue) {
  try { sourceValue = $('Execute Workflow Trigger').first()?.json?.['Source']; } catch(e) { console.error('Parse Response: Trigger source fallback failed:', e.message); }
}
jobData['Source'] = sourceValue || '';

if (jobData._skip) {
  return { json: jobData };
}

let fitScore = 0;
let originalScore = 0;
let scoreCapped = false;
let scoreCapReason = null;
let fitRationale = 'Unable to rate';
let industry = '';
let companyStage = '';
let roleType = '';
let builderEvidence = '';
let maintainerEvidence = '';
let recommendation = '';

const enrichment = jobData._enrichment || {};

function extractJSON(text) {
  let depth = 0;
  let start = -1;
  for (let i = 0; i < text.length; i++) {
    if (text[i] === '{') {
      if (depth === 0) start = i;
      depth++;
    } else if (text[i] === '}') {
      depth--;
      if (depth === 0 && start !== -1) {
        return text.substring(start, i + 1);
      }
    }
  }
  return null;
}

try {
  if (input.content && input.content[0] && input.content[0].text) {
    const content = input.content[0].text;
    const jsonStr = extractJSON(content);

    if (jsonStr) {
      const cleaned = jsonStr
        .replace(/,\s*}/g, '}')
        .replace(/,\s*]/g, ']')
        .replace(/\n/g, ' ')
        .replace(/\t/g, ' ')
        .replace(/"\s+"/g, '", "')
        .replace(/]\s*"/g, '], "')
        .replace(/"\s*\[/g, '": [')
        .replace(/}\s*"/g, '}, "');

      const parsed = JSON.parse(cleaned);

      fitScore = parsed.score || 0;
      originalScore = fitScore;
      roleType = parsed.role_type || '';
      recommendation = parsed.recommendation || '';
      fitRationale = parsed.summary || 'No summary provided';

      // v6.6: CS Hire Readiness Score Capping (Batch 4 Fix 4.3)
      const csHireLikelihood = (parsed.cs_hire_likelihood || '').toLowerCase();
      if (csHireLikelihood === 'unlikely') {
        if (fitScore > 65) {
          scoreCapped = true;
          scoreCapReason = 'Score capped from ' + fitScore + ' to 65: CS hire likelihood is unlikely';
          fitScore = 65;
        }
      } else if (csHireLikelihood === 'low') {
        if (fitScore > 75) {
          scoreCapped = true;
          scoreCapReason = 'Score capped from ' + fitScore + ' to 75: CS hire likelihood is low';
          fitScore = 75;
        }
      }

      // v6.6: Apply funding staleness modifier
      const fundingStalenessModifier = jobData._fundingStalenessModifier || 0;
      if (fundingStalenessModifier < 0) {
        const beforeMod = fitScore;
        fitScore = Math.max(0, fitScore + fundingStalenessModifier);
        const modNote = 'Funding staleness: ' + fundingStalenessModifier + ' (from ' + beforeMod + ' to ' + fitScore + ')';
        scoreCapReason = scoreCapReason ? scoreCapReason + ' | ' + modNote : modNote;
      }
      companyStage = parsed.company_stage_detected || enrichment.fundingStage || '';
      industry = parsed.industry || '';

      if (parsed.builder_evidence) {
        const arr = Array.isArray(parsed.builder_evidence) ? parsed.builder_evidence : [parsed.builder_evidence];
        builderEvidence = arr.slice(0, 3).join('; ');
      }
      if (parsed.maintainer_evidence) {
        const arr = Array.isArray(parsed.maintainer_evidence) ? parsed.maintainer_evidence : [parsed.maintainer_evidence];
        maintainerEvidence = arr.slice(0, 3).join('; ');
      }

      if (parsed.is_dealbreaker && parsed.dealbreaker_reason) {
        fitRationale = `DEALBREAKER: ${parsed.dealbreaker_reason}. ${fitRationale}`;
      }

      // v6.3: Append score breakdown to rationale for transparency
      if (parsed.score_breakdown) {
        const sb = parsed.score_breakdown;
        const breakdownStr = `Stage: ${sb.company_stage_fit || 0}/30, CS Readiness: ${sb.cs_hire_readiness || 0}/25, Role: ${sb.role_mandate || 0}/25, Mission: ${sb.mission_alignment || 0}/20`;
        fitRationale = fitRationale + ' | Breakdown: ' + breakdownStr;
      }

      // v6.3: Append penalties/bonuses if present
      if (parsed.penalties_applied && parsed.penalties_applied.length > 0) {
        fitRationale = fitRationale + ' | Penalties: ' + parsed.penalties_applied.join(', ');
      }
      if (parsed.bonuses_applied && parsed.bonuses_applied.length > 0) {
        fitRationale = fitRationale + ' | Bonuses: ' + parsed.bonuses_applied.join(', ');
      }
    } else {
      fitRationale = 'Could not extract JSON from response';
    }
  } else if (input.error) {
    fitRationale = 'API Error: ' + (input.error.message || JSON.stringify(input.error));
  }
} catch (e) {
  const content = input.content?.[0]?.text || '';
  const scoreMatch = content.match(/"score"\s*:\s*(\d+)/i);
  const roleMatch = content.match(/"role_type"\s*:\s*"(builder|maintainer|hybrid)"/i);
  const recMatch = content.match(/"recommendation"\s*:\s*"(apply|research|skip)"/i);
  const summaryMatch = content.match(/"summary"\s*:\s*"([^"]+)"/i);
  const industryMatch = content.match(/"industry"\s*:\s*"([^"]+)"/i);
  const stageMatch = content.match(/"company_stage_detected"\s*:\s*"([^"]+)"/i);

  if (scoreMatch || summaryMatch) {
    fitScore = scoreMatch ? parseInt(scoreMatch[1]) : 0;
    roleType = roleMatch ? roleMatch[1] : '';
    recommendation = recMatch ? recMatch[1] : '';
    fitRationale = summaryMatch ? summaryMatch[1] : 'Partial parse - see score';
    industry = industryMatch ? industryMatch[1] : '';
    companyStage = stageMatch ? stageMatch[1] : enrichment.fundingStage || '';
  } else {
    fitRationale = 'Parse Error: ' + e.message;
  }
}

// Append enrichment data to rationale
const enrichmentParts = [];
if (enrichment.employeeCount) enrichmentParts.push(`Employees: ${enrichment.employeeCount}`);
if (enrichment.totalFunding) {
  const fundingStr = enrichment.totalFunding >= 1000 ? `$${(enrichment.totalFunding / 1000).toFixed(1)}B` : `$${enrichment.totalFunding}M`;
  enrichmentParts.push(`Funding: ${fundingStr}`);
}
if (enrichment.isPEBacked) enrichmentParts.push('PE-backed');
if (enrichment.isVCBacked) enrichmentParts.push('VC-backed');
if (enrichment.foundedYear) enrichmentParts.push(`Founded: ${enrichment.foundedYear}`);
if (enrichmentParts.length > 0) {
  fitRationale = fitRationale + ' | Enrichment: ' + enrichmentParts.join(', ');
}

// v6.6: Update recommendation based on capped score
if (scoreCapped || (jobData._fundingStalenessModifier && jobData._fundingStalenessModifier < 0)) {
  if (fitScore >= 60) recommendation = 'research';
  else if (fitScore >= 40) recommendation = 'research';
  else recommendation = 'skip';
  if (scoreCapped) fitRationale = '[CAPPED] ' + fitRationale;
}

// v6.6: Append capping reason to rationale
if (scoreCapReason) {
  fitRationale = fitRationale + ' | ' + scoreCapReason;
}

const { _systemPrompt, _userPrompt, _skip, prefilterAnalysis, _enrichment, _braveResultCount, _hasAutoDisqualifier, _networkConnection, _isDeveloperCustomer, _maintainerSignalCount, _builderSignalCount, _lastFundingYear, _yearsSinceLastRound, _fundingRecency, _fundingStalenessModifier, _isCXToolingCompany, _cxToolingSignals, _suspiciousEmployeeCount, _employeeCountFlag, ...cleanJobData } = jobData;

return {
  json: {
    ...cleanJobData,
    'Tide-Pool Score': fitScore,
    'Original Score': scoreCapped ? originalScore : null,
    'Score Capped': scoreCapped,
    'Tide-Pool Rationale': fitRationale,
    'Industry': industry,
    'Company Stage': companyStage,
    'Role Type': roleType,
    'Builder Evidence': builderEvidence,
    'Maintainer Evidence': maintainerEvidence,
    'Recommendation': recommendation,
    // v6.6: Batch 4 fields
    'Funding Recency': jobData._fundingRecency || '',
    'Is CX Tooling Company': jobData._isCXToolingCompany || false,
    'CX Tooling Signals': jobData._cxToolingSignals || '',
    'Suspicious Employee Count': jobData._suspiciousEmployeeCount || false
  }
};

// Prepare data for dedup registration
const airtableRecord = $json;
let parseResponseData = {};
let restoreData = {};
try { parseResponseData = $('Parse Response').item?.json || {}; } catch(e) { parseResponseData = {}; }
try { restoreData = $('Restore Job Data').item?.json || {}; } catch(e) { restoreData = {}; }

// Normalize function for key generation
const normalize = (str) => str ? str.toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';

const company = parseResponseData['Company'] || '';
const title = parseResponseData['Job Title'] || '';
const source = parseResponseData['Source'] || 'Unknown';
const key = `job:${normalize(company)}:${normalize(title)}`;

return {
  json: {
    key: key,
    company: company,
    title: title,
    source: source,
    recordType: 'job',
    airtableRecordId: airtableRecord.id,
    _emailId: parseResponseData._emailId,
    _originalRecord: airtableRecord
  }
};

// Merge _emailId and return final output
const registerResult = $json;
let prepData = {};
try { prepData = $('Prepare Dedup Register').item?.json || {}; } catch(e) { prepData = {}; }

return {
  json: {
    ...prepData._originalRecord,
    _emailId: prepData._emailId,
    _dedupRegistered: registerResult.registered || false
  }
};
